1	import { quote, claim } from "./claim-office.js";
2	import { readFileSync } from "node:fs";
3	
4	const stdinText = readFileSync(0, "utf8");
5	const scenario = JSON.parse(stdinText);
6	const customer = scenario.customer;
7	const steps = scenario.steps;
8	const policies: { items: unknown[] }[] = [];
9	const results: ({ premium: number } | { payout: number })[] = [];
10	try {
11	  for (const step of steps) {
12	    if (step.op === "quote") {
13	      const previousQuoteCount = policies.length;
14	      const premium = quote({ customer, items: step.items, previousQuoteCount });
15	      results.push({ premium });
16	      policies.push({ items: step.items });
17	    } else if (step.op === "claim") {
18	      const policy = policies[step.policy];
19	      const payout = claim({
20	        policy: { items: policy.items as { type: string; material?: string; enchantment?: number }[] },
21	        incident: step.incident,
22	      });
23	      results.push({ payout });
24	    }
25	  }
26	} catch (error) {
27	  process.stderr.write(error instanceof Error ? error.message : String(error));
28	  process.exit(1);
29	}
30	process.stdout.write(JSON.stringify({ results }));
