41	export function quote(input: { customer: { yearsWithMHPCO: number }; items: { type: string; enchantment?: number; cursed?: boolean }[]; previousQuoteCount?: number }): number {
42	  const items = input.items;
43	  for (const item of items) {
44	    if (!(item.type in BASE_PRICE_BY_TYPE)) {
45	      throw new Error(`Unknown item type: ${item.type}`);
46	    }
47	  }
48	  const countByType: Record<string, number> = {};
49	  for (const item of items) {
50	    countByType[item.type] = (countByType[item.type] ?? 0) + 1;
51	  }
52	  let basePrice = 0;
53	  for (const type of Object.keys(countByType)) {
54	    const count = countByType[type];
55	    const formsRuneBlock = RUNE_COMPONENT_TYPES.has(type) && count === RUNE_COMPONENT_BLOCK_SIZE;
56	    if (formsRuneBlock) {
57	      basePrice += RUNE_COMPONENT_BLOCK_PRICE;
58	    } else {
59	      basePrice += count * BASE_PRICE_BY_TYPE[type];
60	    }
61	  }
62	  let highEnchantmentSurcharges = 0;
63	  let cursedSurcharges = 0;
64	  for (const item of items) {
65	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
66	      highEnchantmentSurcharges += BASE_PRICE_BY_TYPE[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE;
67	    }
68	    if (item.cursed === true) {
69	      cursedSurcharges += BASE_PRICE_BY_TYPE[item.type] * CURSE_SURCHARGE_RATE;
70	    }
71	  }
72	  const firstInsuranceSurcharge = basePrice * FIRST_INSURANCE_SURCHARGE_RATE;
73	  const qualifiesForLoyaltyDiscount = input.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
74	  const loyaltyDiscount = qualifiesForLoyaltyDiscount ? basePrice * LOYALTY_DISCOUNT_RATE : 0;
75	  const qualifiesForFollowUpDiscount = (input.previousQuoteCount ?? 0) >= FOLLOWUP_THRESHOLD_PREVIOUS_QUOTES;
76	  const followUpDiscount = qualifiesForFollowUpDiscount ? basePrice * FOLLOWUP_DISCOUNT_RATE : 0;
77	  const premium = basePrice + cursedSurcharges + highEnchantmentSurcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE;
78	  return Math.ceil(premium);
79	}
